    let stmts = match mlpl_parser::parse(&tokens) {
        Ok(s) if s.is_empty() => return String::new(),
        Ok(s) => s,
        Err(e) => return format!("error: {e}"),
    };

    match mlpl_eval::eval_program(&stmts, env) {
        Ok(arr) => format!("{arr}"),
        Err(e) => format!("error: {e}"),
    }
}

