        font-family: var(--mono);
        font-size: 16px;
        font-weight: 700;
        cursor: pointer;
    }
    .help-btn:hover {
        background: var(--surface1);
        border-color: var(--blue);
    }

    /* REPL output area */
    main {
        display: flex;
        flex-direction: column;
        min-height: 0;
    }
    .output {
        flex: 1;
        overflow-y: auto;
        padding: 16px 20px;
    }
    .welcome {
        color: var(--overlay2);
        margin-bottom: 16px;
    }
    .welcome p {
        margin-bottom: 4px;
    }
    .welcome code {
        color: var(--peach);
        background: var(--surface0);
        padding: 1px 6px;
        border-radius: 3px;
    }
    .entry {
        margin-bottom: 8px;
    }
    .input-line {
        color: var(--text);
    }
    .prompt {
        color: var(--green);
        font-weight: 700;
    }
    .output-line {
        color: var(--subtext1);
        white-space: pre;
        margin-left: 0;
        font-family: var(--mono);
        font-size: 15px;
    }
    .output-line.error {
        color: var(--red);
    }

    /* Input row */
    .input-row {
        display: flex;
        align-items: center;
        padding: 12px 20px;
        border-top: 1px solid var(--surface1);
        background: var(--mantle);
        flex-shrink: 0;
    }
    .input-row input {
        flex: 1;
        background: transparent;
        border: none;
        outline: none;
        color: var(--text);
        font-family: var(--mono);
        font-size: 15px;
        margin-left: 4px;
    }

    /* Modal */
    .modal-backdrop {
        position: fixed;
        inset: 0;
        background: rgba(0, 0, 0, 0.7);
        display: flex;
        align-items: center;
        justify-content: center;
        z-index: 200;
    }
    .modal {
        background: var(--mantle);
        border: 1px solid var(--surface1);
        border-radius: 8px;
        width: min(900px, 92vw);
        height: min(80vh, 800px);
        display: flex;
        flex-direction: column;
        box-shadow: 0 10px 40px rgba(0, 0, 0, 0.5);
    }
    .modal-header {
        display: flex;
        align-items: center;
        border-bottom: 1px solid var(--surface1);
        padding: 0 8px;
        flex-shrink: 0;
    }
    .tabs {
        display: flex;
        flex: 1;
    }
    .tab {
        background: transparent;
        border: none;
        color: var(--overlay2);
        font-family: var(--mono);
        font-size: 14px;
        padding: 14px 18px;
        cursor: pointer;
        border-bottom: 2px solid transparent;
    }
    .tab:hover {
        color: var(--text);
    }
    .tab.active {
        color: var(--blue);
        border-bottom-color: var(--blue);
    }
    .close-btn {
        background: transparent;
        border: none;
        color: var(--overlay2);
        font-size: 28px;
        line-height: 1;
        cursor: pointer;
        padding: 8px 14px;
    }
    .close-btn:hover {
        color: var(--red);
    }
    .modal-body {
        flex: 1;
        overflow-y: auto;
        padding: 20px;
    }
    .doc-content {
        font-family: var(--mono);
        font-size: 13px;
        line-height: 1.55;
        color: var(--subtext1);
        white-space: pre-wrap;
        word-break: break-word;
    }
</style>

