use mlpl_wasm::WasmSession;
use wasm_bindgen::JsCast;
use web_sys::{HtmlInputElement, KeyboardEvent};
use yew::prelude::*;

const REPO_URL: &str = "https://github.com/sw-ml-study/sw-mlpl";
const LANG_REFERENCE: &str = include_str!("../../../docs/lang-reference.md");
const USAGE_GUIDE: &str = include_str!("../../../docs/usage.md");

#[derive(Clone, PartialEq)]
struct HistoryEntry {
    input: String,
    output: String,
    is_error: bool,
}

#[derive(Clone, Copy, PartialEq)]
enum DocTab {
    LangReference,
    Usage,
}

#[function_component(App)]
fn app() -> Html {
    let session = use_mut_ref(WasmSession::new);
    let history = use_state(Vec::<HistoryEntry>::new);
    let input_value = use_state(String::new);
    let cmd_history = use_state(Vec::<String>::new);
    let cmd_index = use_state(|| None::<usize>);
    let dialog_open = use_state(|| false);
    let active_tab = use_state(|| DocTab::LangReference);

    let on_submit = {
        let session = session.clone();
        let history = history.clone();
        let input_value = input_value.clone();
        let cmd_history = cmd_history.clone();
        let cmd_index = cmd_index.clone();
        Callback::from(move |line: String| {
            let trimmed = line.trim();
            if trimmed.is_empty() {
                return;
            }

            let mut new_history = (*history).clone();
            let mut new_cmds = (*cmd_history).clone();
            new_cmds.push(trimmed.to_string());

            // Handle REPL commands
            let entry = if trimmed == ":clear" {
                session.borrow().clear();
                new_history.clear();
                cmd_history.set(new_cmds);
                cmd_index.set(None);
                input_value.set(String::new());
                history.set(new_history);
                return;
            } else if trimmed == ":help" {
                HistoryEntry {
                    input: trimmed.to_string(),
                    output: help_text(),
                    is_error: false,
                }
            } else {
                let result = session.borrow().eval(trimmed);
                let is_error = result.starts_with("error:");
                HistoryEntry {
                    input: trimmed.to_string(),
                    output: result,
                    is_error,
                }
            };

            new_history.push(entry);
            history.set(new_history);
            cmd_history.set(new_cmds);
            cmd_index.set(None);
            input_value.set(String::new());
        })
    };

    let on_input = {
        let input_value = input_value.clone();
        Callback::from(move |e: InputEvent| {
            let target: HtmlInputElement = e.target_unchecked_into();
            input_value.set(target.value());
        })
    };

    let on_keydown = {
        let on_submit = on_submit.clone();
        let input_value = input_value.clone();
        let cmd_history = cmd_history.clone();
        let cmd_index = cmd_index.clone();
        Callback::from(move |e: KeyboardEvent| match e.key().as_str() {
            "Enter" => {
                e.prevent_default();
                on_submit.emit((*input_value).clone());
            }
            "ArrowUp" => {
                e.prevent_default();
                let cmds = &*cmd_history;
                if cmds.is_empty() {
                    return;
                }
                let new_idx = match *cmd_index {
                    None => cmds.len() - 1,
                    Some(0) => 0,
                    Some(i) => i - 1,
                };
                cmd_index.set(Some(new_idx));
                input_value.set(cmds[new_idx].clone());
            }
            "ArrowDown" => {
                e.prevent_default();
                let cmds = &*cmd_history;
                match *cmd_index {
                    Some(i) if i + 1 < cmds.len() => {
                        cmd_index.set(Some(i + 1));
                        input_value.set(cmds[i + 1].clone());
                    }
                    Some(_) => {
                        cmd_index.set(None);
                        input_value.set(String::new());
                    }
                    None => {}
                }
            }
            _ => {}
        })
    };

    let open_dialog = {
        let dialog_open = dialog_open.clone();
        Callback::from(move |_| dialog_open.set(true))
    };

    let close_dialog = {
        let dialog_open = dialog_open.clone();
        Callback::from(move |_| dialog_open.set(false))
    };

    let select_lang_tab = {
        let active_tab = active_tab.clone();
        Callback::from(move |_| active_tab.set(DocTab::LangReference))
    };

    let select_usage_tab = {
        let active_tab = active_tab.clone();
        Callback::from(move |_| active_tab.set(DocTab::Usage))
    };

    // Auto-scroll output to bottom on update
    {
        let history_dep = history.clone();
        use_effect_with(history_dep, |_| {
            if let Some(window) = web_sys::window() {
                if let Some(document) = window.document() {
                    if let Some(el) = document.get_element_by_id("output") {
                        el.set_scroll_top(el.scroll_height());
                    }
                    if let Some(el) = document.get_element_by_id("repl-input") {
                        if let Ok(input) = el.dyn_into::<HtmlInputElement>() {
                            let _ = input.focus();
                        }
                    }
                }
            }
            || ()
        });
    }

    let dialog = if *dialog_open {
        let content = match *active_tab {
            DocTab::LangReference => LANG_REFERENCE,
            DocTab::Usage => USAGE_GUIDE,
        };
        let lang_class = if *active_tab == DocTab::LangReference {
            "tab active"
        } else {
            "tab"
        };
        let usage_class = if *active_tab == DocTab::Usage {
            "tab active"
        } else {
            "tab"
        };
        html! {
            <div class="modal-backdrop" onclick={close_dialog.clone()}>
                <div class="modal" onclick={Callback::from(|e: MouseEvent| e.stop_propagation())}>
                    <div class="modal-header">
                        <div class="tabs">
                            <button class={lang_class} onclick={select_lang_tab}>{"Language Reference"}</button>
                            <button class={usage_class} onclick={select_usage_tab}>{"Usage Guide"}</button>
                        </div>
                        <button class="close-btn" onclick={close_dialog} aria-label="Close">{"×"}</button>
                    </div>
                    <div class="modal-body">
                        <pre class="doc-content">{ content }</pre>
                    </div>
                </div>
            </div>
        }
    } else {
        html! {}
    };

    html! {
        <>
            <a class="github-corner" href={REPO_URL} aria-label="View source on GitHub" target="_blank" rel="noopener">
                <svg width="60" height="60" viewBox="0 0 250 250" aria-hidden="true">
                    <path d="M0,0 L115,115 L130,115 L142,142 L250,250 L250,0 Z"></path>
                    <path d="M128.3,109.0 C113.8,99.7 119.0,89.6 119.0,89.6 C122.0,82.7 120.5,78.6 120.5,78.6 C119.2,72.0 123.4,76.3 123.4,76.3 C127.3,80.9 125.5,87.3 125.5,87.3 C122.9,97.6 130.6,101.9 134.4,103.2" fill="currentColor" class="octo-arm"></path>
                    <path d="M115.0,115.0 C114.9,115.1 118.7,116.5 119.8,115.4 L133.7,101.6 C136.9,99.2 139.9,98.4 142.2,98.6 C133.8,88.0 127.5,74.4 143.8,58.0 C148.5,53.4 154.0,51.2 159.7,51.0 C160.3,49.4 163.2,43.6 171.4,40.1 C171.4,40.1 176.1,42.5 178.8,56.2 C183.1,58.6 187.2,61.8 190.9,65.4 C194.5,69.0 197.7,73.2 200.1,77.6 C213.8,80.2 216.3,84.9 216.3,84.9 C212.7,93.1 206.9,96.0 205.4,96.6 C205.1,102.4 203.0,107.8 198.3,112.5 C181.9,128.9 168.3,122.5 157.7,114.1 C157.9,116.9 156.7,120.9 152.7,124.9 L141.0,136.5 C139.8,137.7 141.6,141.9 141.8,141.8 Z" fill="currentColor" class="octo-body"></path>
                </svg>
            </a>
            <header>
                <h1>{"MLPL"}</h1>
                <span>{"v0.2 — Array Programming Language for ML"}</span>
                <button class="help-btn" onclick={open_dialog} aria-label="Show documentation" title="Documentation">{"?"}</button>
            </header>
            <main>
                <div id="output" class="output">
                    <div class="welcome">
                        <p>{"Welcome to MLPL. Type expressions and press Enter."}</p>
                        <p>{"Try: "}<code>{"1 + 2"}</code>{", "}<code>{"iota(5)"}</code>{", "}<code>{"reshape(iota(6), [2, 3])"}</code></p>
                        <p>{"Type "}<code>{":help"}</code>{" for the function list, "}<code>{":clear"}</code>{" to reset, or click "}<code>{"?"}</code>{" for full docs."}</p>
                    </div>
                    { for history.iter().map(render_entry) }
                </div>
                <div class="input-row">
                    <span class="prompt">{"mlpl> "}</span>
                    <input
                        id="repl-input"
                        type="text"
                        autocomplete="off"
                        spellcheck="false"
                        value={(*input_value).clone()}
                        oninput={on_input}
                        onkeydown={on_keydown}
                    />
                </div>
            </main>
            <footer>
                <span>{"MLPL v0.2"}</span>
                <span class="footer-sep">{"·"}</span>
                <a href={REPO_URL} target="_blank" rel="noopener">{"GitHub"}</a>
                <span class="footer-sep">{"·"}</span>
                <span>{"Built with Rust + Yew + WASM"}</span>
            </footer>
            { dialog }
        </>
    }
}

fn render_entry(entry: &HistoryEntry) -> Html {
    let output_class = if entry.is_error {
        "output-line error"
    } else {
        "output-line"
    };
    html! {
        <div class="entry">
            <div class="input-line"><span class="prompt">{"mlpl> "}</span>{ &entry.input }</div>
            <pre class={output_class}>{ &entry.output }</pre>
        </div>
    }
}

fn help_text() -> String {
    [
        "MLPL v0.2 -- Array Programming Language for ML",
        "",
        "Syntax:",
        "  42              scalar literal",
        "  [1, 2, 3]       array literal",
        "  x = expr        assignment",
        "  a + b           arithmetic (+, -, *, /)",
        "  func(args)      function call",
        "  repeat N { }    loop N times",
        "",
        "Built-in functions:",
        "  iota, shape, rank, reshape, transpose",
        "  reduce_add, reduce_mul (with optional axis)",
        "  dot, matmul",
        "  exp, log, sqrt, abs, pow",
        "  sigmoid, tanh_fn",
        "  gt, lt, eq, mean",
        "  zeros, ones, fill",
        "",
        "Commands:",
        "  :help   show this help",
        "  :clear  reset all variables",
    ]
    .join("\n")
}

fn main() {
    yew::Renderer::<App>::new().render();
}

