struct AppState {
    session: std::rc::Rc<std::cell::RefCell<WasmSession>>,
    history: UseStateHandle<Vec<HistoryEntry>>,
    input_value: UseStateHandle<String>,
    cmd_history: UseStateHandle<Vec<String>>,
    cmd_index: UseStateHandle<Option<usize>>,
    dialog_open: UseStateHandle<bool>,
}

impl AppState {
    fn new() -> Self {
        Self {
            session: use_mut_ref(WasmSession::new),
            history: use_state(Vec::<HistoryEntry>::new),
            input_value: use_state(String::new),
            cmd_history: use_state(Vec::<String>::new),
            cmd_index: use_state(|| None::<usize>),
            dialog_open: use_state(|| false),
        }
    }

    fn eval_deps(&self) -> EvalDeps {
        EvalDeps {
            session: self.session.clone(),
            history: self.history.clone(),
            input_value: self.input_value.clone(),
            cmd_history: self.cmd_history.clone(),
            cmd_index: self.cmd_index.clone(),
        }
    }
}

