mod components;
mod demos;
mod handlers;
mod help;
mod state;
mod tutorial;

use components::{
    DocDialog, Footer, GithubCorner, Header, InputRow, TutorialPanel, Welcome,
};
use handlers::{EvalDeps, make_clear, make_keydown, make_oninput, make_run_demo, make_submit};
use mlpl_wasm::WasmSession;
use state::HistoryEntry;
use tutorial::LESSONS;
use wasm_bindgen::JsCast;
use web_sys::HtmlInputElement;
use yew::prelude::*;

const REPO_URL: &str = "https://github.com/sw-ml-study/sw-mlpl";

#[function_component(App)]
fn app() -> Html {
    let session = use_mut_ref(WasmSession::new);
    let history = use_state(Vec::<HistoryEntry>::new);
    let input_value = use_state(String::new);
    let cmd_history = use_state(Vec::<String>::new);
    let cmd_index = use_state(|| None::<usize>);
    let dialog_open = use_state(|| false);
    let lesson_idx = use_state(|| None::<usize>);

    let on_submit = make_submit(EvalDeps {
        session: session.clone(),
        history: history.clone(),
        input_value: input_value.clone(),
        cmd_history: cmd_history.clone(),
        cmd_index: cmd_index.clone(),
    });
    let on_clear = make_clear(session, history.clone());
    let on_demo = make_run_demo(handlers::DemoDeps {
        history: history.clone(),
        lesson_idx: lesson_idx.clone(),
    });

    use_effect_with(history.clone(), |_| {
        scroll_and_focus();
        || ()
    });

    render(RenderArgs {
        on_submit,
        on_clear,
        on_demo,
        input_value,
        cmd_history,
        cmd_index,
        history,
        dialog_open,
        lesson_idx,
    })
}

struct RenderArgs {
    on_submit: Callback<String>,
    on_clear: Callback<MouseEvent>,
    on_demo: Callback<usize>,
    input_value: UseStateHandle<String>,
    cmd_history: UseStateHandle<Vec<String>>,
    cmd_index: UseStateHandle<Option<usize>>,
    history: UseStateHandle<Vec<HistoryEntry>>,
    dialog_open: UseStateHandle<bool>,
    lesson_idx: UseStateHandle<Option<usize>>,
}

fn render(a: RenderArgs) -> Html {
    let on_input = make_oninput(a.input_value.clone());
    let on_keydown = make_keydown(
        a.on_submit.clone(),
        a.input_value.clone(),
        a.cmd_history,
        a.cmd_index,
    );
    let open_dialog = toggle(a.dialog_open.clone(), true);
    let close_dialog = toggle(a.dialog_open.clone(), false);
    let tutorial_active = a.lesson_idx.is_some();
    let on_tutorial = toggle_tutorial(a.lesson_idx.clone());
    let on_prev_lesson = step_lesson(a.lesson_idx.clone(), -1);
    let on_next_lesson = step_lesson(a.lesson_idx.clone(), 1);
    let on_run_example = run_example(a.on_submit.clone(), a.input_value.clone());

    html! {
        <>
            <GithubCorner url={REPO_URL} />
            <Header on_help={open_dialog} on_clear={a.on_clear} on_demo={a.on_demo} on_tutorial={on_tutorial} {tutorial_active} />
            <main>
                { render_tutorial(&a.lesson_idx, on_prev_lesson, on_next_lesson, on_run_example) }
                <div id="output" class="output">
                    { if !tutorial_active { html!{ <Welcome /> } } else { html!{} } }
                    { for a.history.iter().map(render_entry) }
                </div>
                <InputRow value={(*a.input_value).clone()} on_input={on_input} on_keydown={on_keydown} />
            </main>
            <Footer url={REPO_URL} />
            <DocDialog open={*a.dialog_open} on_close={close_dialog} />
        </>
    }
}

fn render_tutorial(
    lesson_idx: &UseStateHandle<Option<usize>>,
    on_prev: Callback<MouseEvent>,
    on_next: Callback<MouseEvent>,
    on_run_example: Callback<String>,
) -> Html {
    match **lesson_idx {
        Some(idx) => {
            let on_close = toggle_lesson_off(lesson_idx.clone());
            html! {
                <TutorialPanel {idx} ..tutorial_props(idx, on_prev, on_next, on_run_example, on_close) />
            }
        }
        None => html! {},
    }
}

fn tutorial_props(
    lesson_idx: usize,
    on_prev: Callback<MouseEvent>,
    on_next: Callback<MouseEvent>,
    on_run_example: Callback<String>,
    on_close: Callback<MouseEvent>,
) -> components::TutorialPanelProps {
    components::TutorialPanelProps {
        lesson_idx,
        on_prev,
        on_next,
        on_run_example,
        on_close,
    }
}

fn toggle(handle: UseStateHandle<bool>, value: bool) -> Callback<MouseEvent> {
    Callback::from(move |_| handle.set(value))
}

fn toggle_tutorial(lesson: UseStateHandle<Option<usize>>) -> Callback<MouseEvent> {
    Callback::from(move |_| {
        if lesson.is_some() {
            lesson.set(None);
        } else {
            lesson.set(Some(0));
        }
    })
}

fn toggle_lesson_off(lesson: UseStateHandle<Option<usize>>) -> Callback<MouseEvent> {
    Callback::from(move |_| lesson.set(None))
}

fn step_lesson(lesson: UseStateHandle<Option<usize>>, delta: i32) -> Callback<MouseEvent> {
    Callback::from(move |_| {
        if let Some(cur) = *lesson {
            let next = (cur as i32 + delta).max(0) as usize;
            if next < LESSONS.len() {
                lesson.set(Some(next));
            }
        }
    })
}

fn run_example(
    on_submit: Callback<String>,
    input_value: UseStateHandle<String>,
) -> Callback<String> {
    Callback::from(move |line: String| {
        input_value.set(line.clone());
        on_submit.emit(line);
    })
}

fn render_entry(entry: &HistoryEntry) -> Html {
    let output_class = if entry.is_error {
        "output-line error"
    } else {
        "output-line"
    };
    html! {
        <div class="entry">
            <div class="input-line"><span class="prompt">{"mlpl> "}</span>{ &entry.input }</div>
            <pre class={output_class}>{ &entry.output }</pre>
        </div>
    }
}

fn scroll_and_focus() {
    if let Some(window) = web_sys::window()
        && let Some(document) = window.document()
    {
        if let Some(el) = document.get_element_by_id("output") {
            el.set_scroll_top(el.scroll_height());
        }
        if let Some(el) = document.get_element_by_id("repl-input")
            && let Ok(input) = el.dyn_into::<HtmlInputElement>()
        {
            let _ = input.focus();
        }
    }
}

fn main() {
    yew::Renderer::<App>::new().render();
}

