33	        Self {
34	            bytes: source.as_bytes(),
35	            source,
36	            pos: 0,
37	            prev_was_value: false,
38	        }
39	    }
40	
41	    fn next_token(&mut self) -> Result<Token, ParseError> {
42	        self.skip_whitespace_and_comments();
43	        if self.pos >= self.bytes.len() {
44	            return Ok(Token {
45	                kind: TokenKind::Eof,
46	                span: Span::new(self.pos, self.pos),
47	            });
48	        }
49	        let b = self.bytes[self.pos];
50	        if b == b'\n' {
51	            let tok = Token {
52	                kind: TokenKind::Newline,
53	                span: Span::new(self.pos, self.pos + 1),
54	            };
55	            self.pos += 1;
56	            self.prev_was_value = false;
57	            return Ok(tok);
58	        }
59	        if let Some(kind) = single_char_token(b) {
60	            let is_val = matches!(kind, TokenKind::RParen | TokenKind::RBracket);
61	            let tok = Token {
62	                kind,
63	                span: Span::new(self.pos, self.pos + 1),
64	            };
65	            self.pos += 1;
66	            self.prev_was_value = is_val;
67	            return Ok(tok);
68	        }
69	        if b == b'-' {
70	            return self.lex_minus();
71	        }
72	        if b.is_ascii_digit() {
73	            return self.lex_digit();
74	        }
75	        if b.is_ascii_alphabetic() || b == b'_' {
76	            return Ok(self.lex_ident());
77	        }
78	        let ch = self.source[self.pos..].chars().next().unwrap();
79	        Err(ParseError::UnexpectedCharacter {
80	            ch,
81	            span: Span::new(self.pos, self.pos + ch.len_utf8()),
82	        })
83	    }
