86	        while self.pos < self.bytes.len() {
87	            let b = self.bytes[self.pos];
88	            if b == b' ' || b == b'\t' {
89	                self.pos += 1;
90	            } else if b == b'#' {
91	                while self.pos < self.bytes.len() && self.bytes[self.pos] != b'\n' {
92	                    self.pos += 1;
93	                }
94	            } else {
95	                break;
96	            }
97	        }
98	    }
