101	        if let Some((tok, end)) = lex_number(self.bytes, self.pos).filter(|_| !self.prev_was_value)
102	        {
103	            let span = Span::new(self.pos, end);
104	            self.pos = end;
105	            self.prev_was_value = true;
106	            return Ok(Token { kind: tok, span });
107	        }
108	        let tok = Token {
109	            kind: TokenKind::Minus,
110	            span: Span::new(self.pos, self.pos + 1),
111	        };
112	        self.pos += 1;
113	        self.prev_was_value = false;
114	        Ok(tok)
115	    }
116	
117	    fn lex_digit(&mut self) -> Result<Token, ParseError> {
118	        if let Some((tok, end)) = lex_number(self.bytes, self.pos) {
119	            let span = Span::new(self.pos, end);
120	            self.pos = end;
121	            self.prev_was_value = true;
122	            return Ok(Token { kind: tok, span });
123	        }
124	        Err(ParseError::InvalidNumber {
125	            span: Span::new(self.pos, self.pos + 1),
126	        })
