142	                TokenKind::Repeat
143	            }
144	            _ => {
145	                self.prev_was_value = true;
146	                TokenKind::Ident(name)
147	            }
148	        };
149	        Token {
150	            kind,
151	            span: Span::new(start, self.pos),
152	        }
