            let trimmed = line.trim();
            if trimmed.starts_with('#') { "" } else { line }
        })
        .collect();
    let source = cleaned.join("\n");
    let trimmed = source.trim();
    if trimmed.is_empty() {
        return;
    }
    for line in content.lines() {
        let t = line.trim();
        if !t.is_empty() && !t.starts_with('#') {
            println!("> {t}");
        }

