use std::io::{self, BufRead, Write};
use std::path::PathBuf;

use mlpl_eval::Environment;
use mlpl_trace::Trace;

/// Where to write SVG output produced by the REPL.
struct SvgOut {
    dir: Option<PathBuf>,
    counter: u32,
}

impl SvgOut {
    fn handle(&mut self, svg: &str) {
        if let Some(dir) = &self.dir {
            self.counter += 1;
            let path = dir.join(format!("svg-{:03}.svg", self.counter));
            match std::fs::write(&path, svg) {
                Ok(()) => println!("[svg: {} bytes -> {}]", svg.len(), path.display()),
                Err(e) => eprintln!("[svg: error writing {}: {e}]", path.display()),
            }
        } else {
            println!("[svg: {} bytes -- pass --svg-out <dir> to save]", svg.len());
        }
    }
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    let mut env = Environment::new();
    let trace_flag = args.iter().any(|a| a == "--trace");
    let svg_dir = args
        .iter()
        .position(|a| a == "--svg-out")
        .and_then(|p| args.get(p + 1))
        .map(PathBuf::from);
    let mut svg_out = SvgOut {
        dir: svg_dir,
        counter: 0,
    };

    if let Some(pos) = args.iter().position(|a| a == "-f" || a == "--file") {
        let path = args.get(pos + 1).unwrap_or_else(|| {
            eprintln!("error: -f requires a file path");
            std::process::exit(1);
        });
        let content = std::fs::read_to_string(path).unwrap_or_else(|e| {
            eprintln!("error reading {path}: {e}");
